import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Calendar","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Calendar | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/calendar"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Calendar | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/calendar"}]]},"headers":[],"relativePath":"user-guide/calendar.md","filePath":"user-guide/calendar.md","lastUpdated":1784758619000}'),r={name:"user-guide/calendar.md"};function s(l,e,i,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="calendar" tabindex="-1">Calendar <a class="header-anchor" href="#calendar" aria-label="Permalink to &quot;Calendar&quot;">​</a></h1><p>Use Calendar to manage <strong>your</strong> personal events. Default view is <strong>Week</strong> (Google-style vertical time slots); <strong>Day</strong>, <strong>Month</strong>, and <strong>Agenda</strong> are also available.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><ul><li>Workspace must have the <strong>Calendar</strong> module installed (included by default).</li><li>Your role needs <code>calendar.view</code> (and <code>create</code> / <code>update</code> / <code>delete</code> for edits).</li></ul><h2 id="visibility" tabindex="-1">Visibility <a class="header-anchor" href="#visibility" aria-label="Permalink to &quot;Visibility&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>What you see</th></tr></thead><tbody><tr><td>Staff (no <code>view_all</code>)</td><td>Only events you created</td></tr><tr><td>Owner / Admin / Manager (<code>calendar.view_all</code>)</td><td>All workspace events</td></tr></tbody></table><p>There is <strong>no calendar assignment</strong>. You cannot assign a calendar to someone else. Booking meetings, hosts, Zoom/Google Meet, and invitees belong to the <strong><a href="/user-guide/meetings">Meetings</a></strong> module (projected onto your Calendar when you are the host).</p><h2 id="create-an-event" tabindex="-1">Create an event <a class="header-anchor" href="#create-an-event" aria-label="Permalink to &quot;Create an event&quot;">​</a></h2><ol><li>Open <strong>Calendar</strong> from the workspace nav.</li><li>Click <strong>New event</strong>, click a day cell (Month), or click a time slot (Week/Day).</li><li>Enter title, start/end, optional description and all-day.</li><li>Save — the event is stored on <strong>your</strong> personal calendar.</li></ol><p>Times use the workspace timezone from settings (not only the browser’s local clock).</p><h2 id="views" tabindex="-1">Views <a class="header-anchor" href="#views" aria-label="Permalink to &quot;Views&quot;">​</a></h2><ul><li><strong>Week</strong> (default) / <strong>Day</strong> — vertical hour slots; events are sized by start/end. Overlapping events share the column side-by-side. Click a slot to create at that hour. <strong>Drag</strong> an event to another day or time to reschedule (requires <code>calendar.update</code>; snaps to 15-minute increments).</li><li><strong>Month</strong> — month grid; chips show start time + title.</li><li><strong>Agenda</strong> — chronological list with start/end times and search.</li></ul><h2 id="cancel-vs-delete" tabindex="-1">Cancel vs delete <a class="header-anchor" href="#cancel-vs-delete" aria-label="Permalink to &quot;Cancel vs delete&quot;">​</a></h2><ul><li><strong>Cancel event</strong> — keeps the record, marks status <code>cancelled</code>.</li><li><strong>Delete</strong> — soft-deletes the event.</li></ul><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><p>The tenant dashboard shows an <strong>Upcoming events</strong> widget (same visibility rules as the list).</p>',16)])])}const m=t(r,[["render",s]]);export{u as __pageData,m as default};
